            }
        }

        long long total_length = 0;
        for (int i = 0; i < 26; i++) {
            total_length = (total_length + result[i]) % MOD;
        }

        return total_length;
    }

    vector<vector<long long>> matrix_multiply(vector<vector<long long>>& a, vector<vector<long long>>& b, int MOD) {
